import time
import anthropic
from dataclasses import dataclass

client = anthropic.Anthropic()

@dataclass
class LatencyMeasurement:
    model: str
    input_tokens_approx: int
    ttft_ms: float
    e2e_ms: float
    output_tokens: int

def measured_stream(model: str, messages: list, system: str = "") -> LatencyMeasurement:
    \"\"\"Stream a Claude response and capture TTFT and E2E latency.\"\"\"
    kwargs = {"model": model, "max_tokens": 2048, "messages": messages, "stream": True}
    if system:
        kwargs["system"] = system

    first_token_time: float | None = None
    output_tokens = 0
    start = time.monotonic()

    with client.messages.stream(**kwargs) as stream:
        for text in stream.text_stream:
            if first_token_time is None and text:
                first_token_time = time.monotonic()
            output_tokens += len(text.split())  # rough approx

        final = stream.get_final_message()

    end = time.monotonic()

    return LatencyMeasurement(
        model=model,
        input_tokens_approx=final.usage.input_tokens,
        ttft_ms=(first_token_time - start) * 1000 if first_token_time else -1,
        e2e_ms=(end - start) * 1000,
        output_tokens=final.usage.output_tokens,
    )

# Track measurements and compute percentiles
measurements: list[LatencyMeasurement] = []

def record(m: LatencyMeasurement):
    measurements.append(m)

def ttft_p95() -> float:
    ttft_values = sorted(m.ttft_ms for m in measurements if m.ttft_ms > 0)
    if not ttft_values:
        return 0.0
    idx = int(len(ttft_values) * 0.95)
    return ttft_values[min(idx, len(ttft_values) - 1)]

# Alert if TTFT P95 approaches SLA threshold
def check_sla_compliance(sla_threshold_ms: float = 1500):
    p95 = ttft_p95()
    if p95 > sla_threshold_ms * 2:
        print(f"ALERT: TTFT P95 = {p95:.0f}ms — EXCEEDS SLA threshold ({sla_threshold_ms}ms)")
    elif p95 > sla_threshold_ms:
        print(f"WARNING: TTFT P95 = {p95:.0f}ms — AT SLA threshold ({sla_threshold_ms}ms)")
    else:
        print(f"OK: TTFT P95 = {p95:.0f}ms")

