# Track SLO compliance against a rolling window

from collections import deque
from dataclasses import dataclass
import time

@dataclass
class RequestResult:
    timestamp: float
    success: bool
    ttft_ms: float

class SLOTracker:
    def __init__(self, window_seconds: int = 3600, slo_target: float = 0.995):
        self.window_seconds = window_seconds
        self.slo_target = slo_target
        self.results: deque[RequestResult] = deque()

    def record(self, success: bool, ttft_ms: float):
        now = time.monotonic()
        self.results.append(RequestResult(now, success, ttft_ms))
        # Evict old results outside the window
        cutoff = now - self.window_seconds
        while self.results and self.results[0].timestamp < cutoff:
            self.results.popleft()

    def current_availability(self) -> float:
        if not self.results:
            return 1.0
        successes = sum(1 for r in self.results if r.success)
        return successes / len(self.results)

    def error_budget_remaining(self) -> float:
        \"\"\"Returns 0.0–1.0 where 1.0 = full budget, 0.0 = budget exhausted.\"\"\"
        allowed_error_rate = 1.0 - self.slo_target
        actual_error_rate = 1.0 - self.current_availability()
        if allowed_error_rate == 0:
            return 0.0 if actual_error_rate > 0 else 1.0
        return max(0.0, 1.0 - actual_error_rate / allowed_error_rate)

    def ttft_p95(self) -> float:
        ttft_vals = sorted(r.ttft_ms for r in self.results if r.success and r.ttft_ms > 0)
        if not ttft_vals:
            return 0.0
        return ttft_vals[int(len(ttft_vals) * 0.95)]

    def status(self) -> str:
        avail = self.current_availability()
        budget = self.error_budget_remaining()
        p95 = self.ttft_p95()
        return (f"Availability: {avail:.3%} | Error budget: {budget:.1%} remaining | "
                f"TTFT P95: {p95:.0f}ms")

# Usage
tracker = SLOTracker(window_seconds=3600, slo_target=0.995)
